const session = $input.first().json;
const trigger = $('Вызов из другого workflow').item.json;
const state = session.state || 'START';
let context = {};
try { context = JSON.parse(session.context || '{}'); } catch(e) {}
let history = [];
try { history = JSON.parse(session.history || '[]'); } catch(e) {}
return [{ json: {
  sessionId: trigger.sessionId,
  userMessage: trigger.userMessage,
  state,
  context,
  history
} }];
